// Busca paginada de notas fiscais na API de origem.
// Faz retry com backoff em erros transitorios (5xx, 429, timeout).
const cfg = $('Configuracoes').first().json;
const base = cfg.baseUrl, contaId = cfg.contaId, doc = cfg.documentoEmpresa, token = cfg.apiToken;
if (!token || !base || !contaId || !doc) throw new Error('Configuracoes nao chegou.');
const helpers = this.helpers;
const sleep = (ms) => new Promise(r => setTimeout(r, ms));
const tamanho = 50;
const maxPaginas = Number(cfg.maxPaginas) > 0 ? Number(cfg.maxPaginas) : 1000;
const todos = [];
const paginasComErro = [];
let pagina = 1;
let totalPaginas = 1;
const buscarPagina = async (p) => {
  const url = `${base}/${contaId}/${doc}/documentos/novos`;
  const maxTentativas = 6;
  for (let t = 1; t <= maxTentativas; t++) {
    try {
      return await helpers.httpRequest({
        method: 'GET', url,
        qs: { Tamanho: tamanho, Pagina: p, Xml: false },
        headers: { Authorization: `Bearer ${token}`, Accept: 'application/json' },
        json: true,
        timeout: 60000,
      });
    } catch (e) {
      const status = e.httpCode || e.statusCode || (e.response && e.response.status);
      const transitorio = !status || status >= 500 || status === 429;
      if (t < maxTentativas && transitorio) { await sleep(2000 * t); continue; }
      return null;
    }
  }
};
do {
  const resp = await buscarPagina(pagina);
  if (resp === null) {
    paginasComErro.push(pagina);
  } else {
    todos.push(...(resp.documentos || []));
    totalPaginas = resp.paginas || totalPaginas;
  }
  pagina++;
  await sleep(300);
} while (pagina <= totalPaginas && pagina <= maxPaginas);
if (paginasComErro.length) console.log('Paginas que falharam, reprocessar depois:', paginasComErro.join(', '));
if (!todos.length && paginasComErro.length) throw new Error('Nenhum documento: todas as paginas falharam: ' + paginasComErro.join(', '));
return todos.map(d => ({ json: d }));

// Filtra por data de corte e remove duplicatas internas (a API pode repetir registros).
const cfg = $('Configuracoes').first().json;
const dataCorte = new Date(cfg.dataCorte);
const vistos = new Set();
const out = [];
for (const item of $input.all()) {
  const doc = item.json;
  // 1) somente notas do tipo desejado
  if (doc.modelo !== 'NF') continue;
  // 2) filtro por data de corte
  const dtStr = doc.data_emissao;
  if (!dtStr || new Date(dtStr) < dataCorte) continue;
  // 3) dedup interno pela chave
  if (vistos.has(doc.chave)) continue;
  vistos.add(doc.chave);
  out.push({ json: doc });
}
return out;

// Normaliza os campos do XML + dados da API em um registro plano.
const apiItems = $('Filtrar por Data de Corte').all();
const inputs = $input.all();
const num = (v) => (v === undefined || v === null || v === '') ? null : Number(v);
const out = [];
for (let i = 0; i < inputs.length; i++) {
  const root = inputs[i].json;
  const api = apiItems[i] ? apiItems[i].json : {};
  const proc = root.notaProc || root;
  const nota = proc.Nota || proc;
  const inf = nota.infNota || {};
  const ide = inf.ide || {};
  const emit = inf.emitente || {};
  const dest = inf.destinatario || {};
  let det = inf.det || {};
  if (Array.isArray(det)) det = det[0] || {};
  const prod = det.produto || {};
  const total = (inf.total && inf.total.tributos) || {};
  const prot = (proc.protNota && proc.protNota.infProt) || {};
  const idAttr = inf.$ && inf.$.Id ? String(inf.$.Id).replace(/^NF/, '') : null;
  const chaveXml = prot.chave || idAttr;
  out.push({ json: {
    chave: api.chave || chaveXml,
    numero_documento: ide.numero ?? null,
    nome_emitente: emit.nome ?? null,
    documento_emitente: emit.cnpj ?? emit.cpf ?? null,
    data_emissao: ide.dataEmissao ?? null,
    codigo_operacao: prod.codigoOperacao ?? null,
    natureza_operacao: ide.naturezaOperacao ?? null,
    valor_produtos: num(total.valorProdutos),
    valor_frete: num(total.valorFrete),
    valor_impostos: num(total.valorImpostos),
    valor_total: num(total.valorTotal),
    documento_destinatario: dest.cnpj ?? null,
    modelo: String(api.modelo ?? ide.modelo ?? ''),
    status: String(api.status ?? ''),
    tipo: String(api.tipo ?? ide.tipo ?? '')
  }});
}
return out;
